  {
    id: "binocular",
    name: "Binocular",
    subtitle: "dirección de la empresa",
    avatar: "B",
    color: "#2E86DE",
    pinned: false,
    worktree: path.join(ESPEC, "binocular"),
  },
  {
    id: "rebuss",
    name: "REBUSS",
    subtitle: "CTO de REBUSS",
    avatar: "R",
    color: "#E67E22",
    pinned: false,
    worktree: path.join(ESPEC, "rebuss"),
