  margin-top: 1px;
}

.chat-actions {
  display: flex;
  gap: 4px;
}

.icon-btn {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  color: var(--text-secondary);
  font-size: 16px;
}

.icon-btn:hover {
  background: rgba(255, 255, 255, 0.05);
}

.messages {
  flex: 1 1 auto;
  overflow-y: auto;
  padding: 16px 14% 10px;
  display: flex;
  flex-direction: column;
  gap: 2px;
  scroll-behavior: smooth;
}

.day-sep {
  align-self: center;
  margin: 12px 0;
  padding: 5px 12px;
  background: rgba(11, 20, 26, 0.85);
  border-radius: 6px;
  color: var(--text-secondary);
  font-size: 12px;
  letter-spacing: 0.3px;
}

.bubble {
  max-width: 72%;
  padding: 7px 10px 8px;
  border-radius: var(--bubble-radius);
  position: relative;
  word-wrap: break-word;
  white-space: pre-wrap;
  line-height: 1.35;
  font-size: 14.5px;
  box-shadow: 0 1px 0.5px rgba(0, 0, 0, 0.25);
  animation: pop 140ms ease-out;
}

@keyframes pop {
  from {
    opacity: 0;
    transform: translateY(4px);
  }
  to {
    opacity: 1;
    transform: none;
  }
}

.bubble.out {
  align-self: flex-end;
  background: var(--bg-bubble-out);
  border-top-right-radius: 0;
}

.bubble.in {
  align-self: flex-start;
  background: var(--bg-bubble-in);
  border-top-left-radius: 0;
}

.bubble .time {
  display: inline-block;
  margin-left: 8px;
  font-size: 10.5px;
  color: rgba(255, 255, 255, 0.45);
  vertical-align: bottom;
  line-height: 1;
  position: relative;
  top: 4px;
  float: right;
}

.bubble .content {
  display: inline;
}

.typing {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  margin-left: 4px;
}
.typing span {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-secondary);
  animation: blink 1.2s infinite ease-in-out both;
}
.typing span:nth-child(2) {
  animation-delay: 0.15s;
}
.typing span:nth-child(3) {
  animation-delay: 0.3s;
}
@keyframes blink {
  0%,
  80%,
  100% {
    opacity: 0.3;
  }
  40% {
    opacity: 1;
  }
}

.tool-chip {
  align-self: flex-start;
  font-size: 11px;
  color: var(--text-muted);
  background: rgba(255, 255, 255, 0.04);
  padding: 2px 8px;
  border-radius: 10px;
  margin: 2px 0 6px;
  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
}

.composer {
  display: flex;
  align-items: flex-end;
  gap: 10px;
  padding: 10px 14px;
  background: var(--bg-composer);
  border-top: 1px solid var(--divider);
}

.composer-input {
  flex: 1 1 auto;
  background: var(--bg-input);
  color: var(--text-primary);
  border: 0;
  border-radius: 10px;
  padding: 10px 14px;
  resize: none;
  outline: none;
  max-height: 160px;
  line-height: 1.4;
  font-size: 15px;
}

.composer-input::placeholder {
  color: var(--text-muted);
}

.send-btn {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: var(--accent);
  color: #fff;
  display: grid;
  place-items: center;
  flex-shrink: 0;
  transition: transform 120ms ease;
}

.send-btn:hover {
  transform: scale(1.04);
}

.send-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
  transform: none;
}

.empty {
  flex: 1 1 auto;
  display: grid;
  place-items: center;
  color: var(--text-muted);
  font-size: 14px;
  text-align: center;
  padding: 32px;
}

.empty .big {
  font-size: 48px;
  margin-bottom: 8px;
}

/* Responsive */
@media (max-width: 780px) {
  :root {
    --sidebar-width: 100%;
  }
  .app {
    grid-template-columns: 1fr;
  }
  .chat {
    display: none;
  }
  .app.show-chat .sidebar {
    display: none;
  }
  .app.show-chat .chat {
    display: flex;
  }
  .back-btn {
    display: inline-block;
  }
  .messages {
    padding: 12px 4% 8px;
  }
  .bubble {
    max-width: 85%;
  }
}

/* Scrollbars */
.contacts::-webkit-scrollbar,
.messages::-webkit-scrollbar {
  width: 8px;
}
.contacts::-webkit-scrollbar-thumb,
.messages::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.06);
  border-radius: 4px;
}

