}

.composer-input {
  flex: 1 1 auto;
  background: var(--bg-input);
  color: var(--text-primary);
  border: 0;
  border-radius: 10px;
  padding: 10px 14px;
  resize: none;
  outline: none;
  max-height: 160px;
  line-height: 1.4;
  font-size: 15px;
}

.composer-input::placeholder {
  color: var(--text-muted);
}

.send-btn {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: var(--accent);
  color: #fff;
  display: grid;
  place-items: center;
  flex-shrink: 0;
  transition: transform 120ms ease;
}

.send-btn:hover {
  transform: scale(1.04);
}

.send-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
  transform: none;
}

.empty {
  flex: 1 1 auto;
  display: grid;
  place-items: center;
  color: var(--text-muted);
  font-size: 14px;
  text-align: center;
  padding: 32px;
}

.empty .big {
  font-size: 48px;
  margin-bottom: 8px;
}

/* Responsive */
@media (max-width: 780px) {
  :root {
    --sidebar-width: 100%;
  }
  .app {
    grid-template-columns: 1fr;
  }
  .chat {
    display: none;
  }
  .app.show-chat .sidebar {
    display: none;
  }
  .app.show-chat .chat {
    display: flex;
  }
  .back-btn {
    display: inline-block;
  }
  .messages {
    padding: 12px 4% 8px;
  }
  .bubble {
    max-width: 85%;
  }
}

/* Scrollbars */
.contacts::-webkit-scrollbar,
.messages::-webkit-scrollbar {
  width: 8px;
}
.contacts::-webkit-scrollbar-thumb,
.messages::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.06);
  border-radius: 4px;
}

