// Partner — WhatsApp-style chat with the Cristóbal multi-specialist backend.

const $ = (sel) => document.querySelector(sel);
const $$ = (sel) => Array.from(document.querySelectorAll(sel));

const state = {
  contacts: [],
  current: null,
  sending: false,
};

const fmtTime = (ts) => {
  const d = new Date(ts);
  return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
};

const fmtDay = (ts) => {
  const d = new Date(ts);
  const today = new Date();
  const sameDay =
    d.getFullYear() === today.getFullYear() &&
    d.getMonth() === today.getMonth() &&
    d.getDate() === today.getDate();
  if (sameDay) return "Hoy";
  const yest = new Date(today);
  yest.setDate(today.getDate() - 1);
  const isYest =
    d.getFullYear() === yest.getFullYear() &&
    d.getMonth() === yest.getMonth() &&
    d.getDate() === yest.getDate();
  if (isYest) return "Ayer";
  return d.toLocaleDateString([], { day: "2-digit", month: "short", year: "numeric" });
};

// ---------------- contacts ----------------
async function loadContacts() {
  const res = await fetch("/api/contacts");
  const list = await res.json();
  state.contacts = list;
  renderContacts();
}

function renderContacts(filter = "") {
  const ul = $("#contacts");
  ul.innerHTML = "";
  const q = filter.trim().toLowerCase();
  const filtered = state.contacts.filter((c) =>
    !q || c.name.toLowerCase().includes(q) || c.subtitle.toLowerCase().includes(q),
  );
  const sorted = [...filtered].sort((a, b) => Number(b.pinned) - Number(a.pinned));
  for (const c of sorted) {
    const li = document.createElement("li");
    li.className = "contact" + (state.current?.id === c.id ? " active" : "");
    li.dataset.id = c.id;
    li.innerHTML = `
      <div class="avatar" style="background:${c.color}">${c.avatar}</div>
      <div class="contact-meta">
        <div class="contact-row">
          <div class="contact-name">${escapeHtml(c.name)}${c.pinned ? ' <span class="pin">📌</span>' : ""}</div>
        </div>
        <div class="contact-sub">${escapeHtml(c.subtitle)}</div>
      </div>
    `;
    li.addEventListener("click", () => selectContact(c.id));
    ul.appendChild(li);
  }
}

// ---------------- messages ----------------
async function selectContact(id) {
  const contact = state.contacts.find((c) => c.id === id);
  if (!contact) return;
  state.current = contact;
  document.body && $(".app").classList.add("show-chat");
  renderContacts($("#search").value || "");
  $("#chat-name").textContent = contact.name;
  $("#chat-sub").textContent = contact.subtitle;
  const av = $("#chat-avatar");
  av.textContent = contact.avatar;
  av.style.background = contact.color;
  await loadMessages(contact.id);
  $("#composer-input").focus();
}

async function loadMessages(id) {
  const res = await fetch(`/api/messages/${id}`);
  const list = await res.json();
  renderMessages(list);
}

function renderMessages(list) {
  const box = $("#messages");
  box.innerHTML = "";
  if (!list.length) {
    box.innerHTML = `
      <div class="empty">
        <div>
          <div class="big">💬</div>
          <div>Sin mensajes todavía.</div>
          <div style="opacity:.6;margin-top:6px">Escribe abajo para empezar.</div>
        </div>
      </div>`;
    return;
  }
  let lastDay = null;
  for (const m of list) {
    const day = fmtDay(m.ts);
    if (day !== lastDay) {
      const sep = document.createElement("div");
      sep.className = "day-sep";
      sep.textContent = day;
      box.appendChild(sep);
      lastDay = day;
    }
    box.appendChild(bubbleEl(m));
  }
  scrollToBottom();
}

function bubbleEl({ role, content, ts }) {
  const el = document.createElement("div");
  el.className = "bubble " + (role === "user" ? "out" : "in");
  const c = document.createElement("span");
  c.className = "content";
  c.textContent = content;
  const t = document.createElement("span");
  t.className = "time";
  t.textContent = fmtTime(ts);
  el.appendChild(c);
  el.appendChild(t);
  return el;
}

function scrollToBottom() {
  const box = $("#messages");
  box.scrollTop = box.scrollHeight;
}

function escapeHtml(s) {
  return String(s).replace(/[&<>"']/g, (m) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" })[m]);
}

// ---------------- send ----------------
async function sendMessage() {
  if (state.sending) return;
  const input = $("#composer-input");
  const text = input.value.trim();
  if (!text || !state.current) return;

  state.sending = true;
  $("#send-btn").disabled = true;
  input.value = "";
  autoGrow(input);

  // If "empty" state is showing, nuke it.
  if ($("#messages .empty")) $("#messages").innerHTML = "";

  // User bubble immediately.
  const userMsg = { role: "user", content: text, ts: Date.now() };
  $("#messages").appendChild(bubbleEl(userMsg));
  scrollToBottom();

  // Assistant bubble with typing indicator; fill in from stream.
  const aBubble = document.createElement("div");
  aBubble.className = "bubble in";
  const aContent = document.createElement("span");
  aContent.className = "content";
  const typing = document.createElement("span");
  typing.className = "typing";
  typing.innerHTML = "<span></span><span></span><span></span>";
  aContent.appendChild(typing);
  const aTime = document.createElement("span");
  aTime.className = "time";
  aBubble.appendChild(aContent);
  aBubble.appendChild(aTime);
  $("#messages").appendChild(aBubble);
  scrollToBottom();

  let buffer = "";
  let finalized = false;
  const contactId = state.current.id;

  try {
    const res = await fetch(`/api/chat/${contactId}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ message: text }),
    });
    if (!res.ok || !res.body) {
      throw new Error(`HTTP ${res.status}`);
    }

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let sseBuf = "";

    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      sseBuf += decoder.decode(value, { stream: true });
      let idx;
      while ((idx = sseBuf.indexOf("\n\n")) !== -1) {
        const raw = sseBuf.slice(0, idx);
        sseBuf = sseBuf.slice(idx + 2);
        const lines = raw.split("\n");
        let event = "message";
        let data = "";
        for (const l of lines) {
          if (l.startsWith("event:")) event = l.slice(6).trim();
          else if (l.startsWith("data:")) data += l.slice(5).trim();
        }
        if (!data) continue;
        let payload;
        try {
          payload = JSON.parse(data);
        } catch {
          continue;
        }
        if (event === "delta" && payload.text) {
          if (typing.parentNode) typing.remove();
          buffer += payload.text;
          aContent.textContent = buffer;
          scrollToBottom();
        } else if (event === "tool_start") {
          const chip = document.createElement("div");
          chip.className = "tool-chip";
          chip.textContent = `⚙ ${payload.name}`;
          aBubble.before(chip);
          scrollToBottom();
        } else if (event === "error") {
          buffer += `\n⚠ ${payload.message}`;
          aContent.textContent = buffer;
        } else if (event === "end") {
          finalized = true;
          aTime.textContent = fmtTime(Date.now());
          if (typing.parentNode) typing.remove();
          if (!buffer) aContent.textContent = "(sin respuesta)";
        }
      }
    }
  } catch (e) {
    if (typing.parentNode) typing.remove();
    aContent.textContent = `⚠ Error: ${e.message}`;
  } finally {
    if (!finalized) {
      aTime.textContent = fmtTime(Date.now());
      if (typing.parentNode) typing.remove();
    }
    state.sending = false;
    $("#send-btn").disabled = false;
    input.focus();
  }
}

// ---------------- composer UX ----------------
function autoGrow(el) {
  el.style.height = "auto";
  el.style.height = Math.min(el.scrollHeight, 160) + "px";
}

function wireUI() {
  const input = $("#composer-input");
  input.addEventListener("input", () => autoGrow(input));
  input.addEventListener("keydown", (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  });
  $("#send-btn").addEventListener("click", sendMessage);
  $("#search").addEventListener("input", (e) => renderContacts(e.target.value));
  $("#back-btn").addEventListener("click", () => {
    $(".app").classList.remove("show-chat");
  });
  $("#clear-btn").addEventListener("click", async () => {
    if (!state.current) return;
    if (!confirm(`¿Borrar historial con ${state.current.name}? Esta acción no se deshace.`)) return;
    await fetch(`/api/messages/${state.current.id}`, { method: "DELETE" });
    await loadMessages(state.current.id);
  });
}

// ---------------- boot ----------------
async function boot() {
  wireUI();
  await loadContacts();
  // Pre-select the pinned one if any.
  const pinned = state.contacts.find((c) => c.pinned) || state.contacts[0];
  if (pinned) selectContact(pinned.id);
  else renderMessages([]);
}

boot().catch((e) => {
  console.error(e);
  alert(`Error cargando Partner: ${e.message}`);
});

