import express from "express";
import { spawn } from "node:child_process";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { randomUUID } from "node:crypto";
import { CONTACTS, getContact } from "./contacts.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const ROOT = path.resolve(__dirname, "..");
const PUBLIC = path.join(ROOT, "frontend", "public");
const SESSIONS = path.join(ROOT, "sessions");

fs.mkdirSync(SESSIONS, { recursive: true });

const app = express();
app.use(express.json({ limit: "1mb" }));
app.use(express.static(PUBLIC));
app.use("/frontend", express.static(path.join(ROOT, "frontend")));

// ---------- contact metadata endpoint ----------
app.get("/api/contacts", (_req, res) => {
  res.json(
    CONTACTS.map(({ id, name, subtitle, avatar, color, pinned }) => ({
      id,
      name,
      subtitle,
      avatar,
      color,
      pinned,
    })),
  );
});

// ---------- history per contact ----------
function historyFile(id) {
  return path.join(SESSIONS, `${id}.jsonl`);
}
function sessionFile(id) {
  return path.join(SESSIONS, `${id}.session`);
}

function readHistory(id) {
  const f = historyFile(id);
  if (!fs.existsSync(f)) return [];
  return fs
    .readFileSync(f, "utf8")
    .split("\n")
    .filter(Boolean)
    .map((l) => {
      try {
        return JSON.parse(l);
      } catch {
        return null;
      }
    })
    .filter(Boolean);
}

function appendHistory(id, entry) {
  fs.appendFileSync(historyFile(id), JSON.stringify(entry) + "\n");
}

function getSessionId(id) {
  const f = sessionFile(id);
  if (fs.existsSync(f)) return fs.readFileSync(f, "utf8").trim();
  return null;
}
function setSessionId(id, sid) {
  fs.writeFileSync(sessionFile(id), sid);
}

app.get("/api/messages/:id", (req, res) => {
  const contact = getContact(req.params.id);
  if (!contact) return res.status(404).json({ error: "unknown contact" });
  res.json(readHistory(contact.id));
});

// ---------- send message + stream model response ----------
app.post("/api/chat/:id", async (req, res) => {
  const contact = getContact(req.params.id);
  if (!contact) return res.status(404).json({ error: "unknown contact" });
  const message = (req.body?.message ?? "").toString();
  if (!message.trim()) return res.status(400).json({ error: "empty message" });

  // persist user message
  const userEntry = {
    role: "user",
    content: message,
    ts: Date.now(),
  };
  appendHistory(contact.id, userEntry);

  // SSE setup
  res.setHeader("Content-Type", "text/event-stream");
  res.setHeader("Cache-Control", "no-cache, no-transform");
  res.setHeader("Connection", "keep-alive");
  res.setHeader("X-Accel-Buffering", "no");
  res.flushHeaders?.();

  const send = (event, data) => {
    res.write(`event: ${event}\n`);
    res.write(`data: ${JSON.stringify(data)}\n\n`);
  };

  let sessionId = getSessionId(contact.id);
  const isFirst = !sessionId;
  if (isFirst) sessionId = randomUUID();

  // Restricted toolset: the Cristóbal can inspect its own branch (Read, Glob,
  // Grep) but cannot edit files or run shell commands. This keeps the backend
  // from becoming an unattended agent loop and makes auto-approval safe.
  const args = [
    "--print",
    "--output-format",
    "stream-json",
    "--verbose",
    "--include-partial-messages",
    "--permission-mode",
    "acceptEdits",
    "--allowedTools",
    "Read,Glob,Grep",
  ];
  if (isFirst) {
    args.push("--session-id", sessionId);
  } else {
    args.push("--resume", sessionId);
  }
  args.push(message);

  console.log(`[partner] ${contact.id} <- "${message.slice(0, 60).replace(/\n/g, " ")}"${message.length > 60 ? "…" : ""}`);
  const child = spawn("claude", args, {
    cwd: contact.worktree,
    env: { ...process.env },
    stdio: ["ignore", "pipe", "pipe"],
  });

  send("start", { contact: contact.id, sessionId, isFirst });

  let buffer = "";
  let assistantText = "";

  child.stdout.on("data", (chunk) => {
    buffer += chunk.toString("utf8");
    let idx;
    while ((idx = buffer.indexOf("\n")) !== -1) {
      const line = buffer.slice(0, idx).trim();
      buffer = buffer.slice(idx + 1);
      if (!line) continue;
      let evt;
      try {
        evt = JSON.parse(line);
      } catch {
        continue;
      }
      handleStreamEvent(evt);
    }
  });

  function handleStreamEvent(evt) {
    // stream-json emits several event kinds. We only forward textual deltas
    // and the final result, keeping the wire thin for the UI.
    if (evt.type === "stream_event" && evt.event) {
      const e = evt.event;
      if (e.type === "content_block_delta" && e.delta?.type === "text_delta") {
        const t = e.delta.text || "";
        assistantText += t;
        send("delta", { text: t });
      } else if (e.type === "content_block_start" && e.content_block?.type === "tool_use") {
        send("tool_start", { name: e.content_block.name, id: e.content_block.id });
      } else if (e.type === "content_block_stop") {
        send("block_stop", {});
      }
    } else if (evt.type === "assistant" && evt.message?.content) {
      // Non-partial assistant message. If we never got deltas, use this.
      if (!assistantText) {
        for (const part of evt.message.content) {
          if (part.type === "text") {
            assistantText += part.text || "";
            send("delta", { text: part.text || "" });
          }
        }
      }
    } else if (evt.type === "result") {
      // Final event with the full text.
      if (!assistantText && evt.result) {
        assistantText = evt.result;
        send("delta", { text: evt.result });
      }
    } else if (evt.type === "system" && evt.session_id) {
      // Claude echoes the effective session id; trust it.
      sessionId = evt.session_id;
    }
  }

  child.stderr.on("data", (chunk) => {
    const t = chunk.toString("utf8");
    console.log(`[partner] stderr: ${t.slice(0, 300)}`);
    if (/error|Error|failed|refused/i.test(t)) {
      send("stderr", { text: t });
    }
  });

  child.on("close", (code) => {
    console.log(`[partner] child exit code=${code} assistantLen=${assistantText.length}`);
    if (sessionId) setSessionId(contact.id, sessionId);
    const assistantEntry = {
      role: "assistant",
      content: assistantText || "(sin respuesta)",
      ts: Date.now(),
      exitCode: code,
    };
    appendHistory(contact.id, assistantEntry);
    send("end", { exitCode: code, sessionId });
    res.end();
  });

  child.on("error", (err) => {
    send("error", { message: err.message });
    res.end();
  });

  // Kill the child only when the *response* is aborted before finishing —
  // not when the full lifecycle closes normally. Using res.on('close') with a
  // flag that flips on child exit avoids killing an already-completed child.
  let childDoneNormally = false;
  child.on("exit", () => {
    childDoneNormally = true;
  });
  res.on("close", () => {
    if (!childDoneNormally && !child.killed) {
      console.log(`[partner] response aborted, killing child`);
      child.kill("SIGTERM");
    }
  });
});

// ---------- danger zone: wipe one contact's memory ----------
app.delete("/api/messages/:id", (req, res) => {
  const contact = getContact(req.params.id);
  if (!contact) return res.status(404).json({ error: "unknown contact" });
  try {
    fs.rmSync(historyFile(contact.id), { force: true });
    fs.rmSync(sessionFile(contact.id), { force: true });
    res.json({ ok: true });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// ---------- root ----------
app.get("/", (_req, res) => {
  res.sendFile(path.join(PUBLIC, "index.html"));
});

const PORT = Number(process.env.PORT) || 4050;
const HOST = process.env.HOST || "0.0.0.0";
app.listen(PORT, HOST, () => {
  console.log(`[partner] listening on http://${HOST}:${PORT}`);
  console.log(`[partner] sessions dir: ${SESSIONS}`);
  console.log(`[partner] contacts: ${CONTACTS.map((c) => c.id).join(", ")}`);
});

